import{c as a,bn as r,aU as e,aX as d,y as l,a3 as h}from"./chunks/framework.EkwLm6yr.js";const m=JSON.parse('{"title":"间忏","description":"","frontmatter":{"order":3},"headers":[],"relativePath":"地图/幽冥血海/间忏.md","filePath":"地图/幽冥血海/间忏.md","lastUpdated":0}'),n={name:"地图/幽冥血海/间忏.md"};function i(b,t,s,o,c,x){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="间忏" tabindex="-1">间忏 <a class="header-anchor" href="#间忏" aria-label="Permalink to “间忏”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">落情草</td><td style="text-align:center;">碧血晶</td><td style="text-align:center;">厄蛛丝</td></tr></tbody></table><h2 id="罗浮山" tabindex="-1">罗浮山 <a class="header-anchor" href="#罗浮山" aria-label="Permalink to “罗浮山”">​</a></h2><h3 id="草鬼婆母" tabindex="-1">草鬼婆母 <a class="header-anchor" href="#草鬼婆母" aria-label="Permalink to “草鬼婆母”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>针蛊：将毒液缠绕在针上，朝敌人方向散形扔出3个毒针</td></tr><tr><td>迷迭蛊<strong>：</strong>召唤2个蛊毒，追踪敌人移动3秒，若碰到敌人使其晕眩</td></tr><tr><td>石头蛊：召唤1个石蛊怪<br>石蛊怪技能：朝前方跳起，短暂滞空后落地，给敌人造成伤害并晕眩，同时植入石蛊buff（3层以后额外扣血）</td></tr><tr><td>蛊虫术：在前方释放1只蛊虫<br>蛊虫普攻1：朝前方撕咬<br>蛊虫技能1：钻入地下后朝前方急速移动，一段时间后钻出地面<br>蛊虫技能2：一段时间后，若蛊虫未被打死，蛊虫会自爆在当前位置形成毒雾</td></tr><tr><td>妖蛊术：召唤多道毒球降落（降落过程中可用普攻打破），落地会爆炸并形成大面积毒区</td></tr><tr><td>蝶梦蛊：召唤蝴蝶包裹自身入梦（霸体并免疫负面，受到伤害使敌人扣蓝，入梦期间会将受到的伤害储存起来），入梦结束后获得蝶盾（护盾期间霸体，蝶盾会加成入梦期间储存起来的受伤值）</td></tr></tbody></table><p>掉落道具：间忏防具制作书</p><h2 id="岁暮荒园" tabindex="-1">岁暮荒园 <a class="header-anchor" href="#岁暮荒园" aria-label="Permalink to “岁暮荒园”">​</a></h2><h3 id="冥蛊师" tabindex="-1">冥蛊师 <a class="header-anchor" href="#冥蛊师" aria-label="Permalink to “冥蛊师”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：技能命中会给敌人施加蛊蚀标记，下次攻击根据所叠层数造成额外伤害</td></tr><tr><td>肆意撞击：挺起肚子前顶，晕眩攻击到的敌人</td></tr><tr><td>蛊虫迷雾：朝前发射一团腐蚀毒气，毒气击中敌人会在其身后爆炸，形成大范围毒雾并施加中毒效果</td></tr><tr><td>虫魔帐网：在敌人头顶落下柱状虫帐，虫帐会短暂跟随敌人移动。自身血量低时虫帐出现会有不同变化</td></tr><tr><td>泰山压顶：原地起跳，随后从上空朝敌人迅速坐下，坠地后在地面上产生一团毒气</td></tr><tr><td>腐蚀奏鸣：大幅度甩铃，获得高额减伤并释放多个虫帐和腐蚀毒气</td></tr><tr><td>黑雾毒爆：摆出受击姿势，持续一段时间。期间被打时自身会发生爆炸，并在攻击者的位置产生会残留的毒雾，自身则瞬移至场景随机点出现。待在毒雾内会中毒，受到高额减速和满层的蛊蚀印记</td></tr></tbody></table><p>掉落道具：间忏武器制作书（第一心法）</p><h2 id="岁暮荒园隐藏" tabindex="-1">岁暮荒园隐藏 <a class="header-anchor" href="#岁暮荒园隐藏" aria-label="Permalink to “岁暮荒园隐藏”">​</a></h2><p>第二波怪，吃到免疫毒气的buff后在沙地S+K向下，向左走攻击蛇</p><p>第三波怪，吃到免疫毒气的buff后在沙地S+K向下，向右走攻击蛇</p><p>攻击完两条蛇，开启<strong>隐藏入口</strong></p><img src="'+l+'" alt="岁暮荒园隐藏" style="zoom:50%;"><h3 id="蛇骨婆母" tabindex="-1">蛇骨婆母 <a class="header-anchor" href="#蛇骨婆母" aria-label="Permalink to “蛇骨婆母”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：蛇骨婆母死亡后会分裂成绿蛇婆母和红蛇婆母</td></tr><tr><td>蛇蛰迅击：下蹲蓄力后向前扑出，随后手臂上的双蛇一左一右同时啃咬</td></tr><tr><td>狂舞蛇尾：转动一周，身上巨蟒尾巴围绕自身甩动，对周边范围内的敌人造成伤害并击飞</td></tr><tr><td>锁敌蛇缚：手掌拍地，从地底窜出一条巨蟒盘旋缠绕捆绑敌人，随后从手中接连发射两条灵蛇攻击</td></tr><tr><td>眩目石身：石化自身，对攻击者造成晕眩和反伤，随后石像爆炸并瞬移至攻击者身边出现</td></tr></tbody></table><p>掉落道具：间忏武器制作书（第二心法）</p><h3 id="绿蛇婆母" tabindex="-1">绿蛇婆母 <a class="header-anchor" href="#绿蛇婆母" aria-label="Permalink to “绿蛇婆母”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：若未在击败青蛇分身的5s内击败红蛇婆母，则二者会合体变回蛇骨婆母，每次合体后血量减半</td></tr><tr><td>隐蛇之咬：召唤虚影蛇头从地面冒出后啃咬</td></tr><tr><td>潜影蛇手：高高跃起，瞬移至敌人斜上方头顶位置释放潜影蛇手</td></tr><tr><td>腐败毒蝮：吐出一滩毒液，毒液附带缚地效果：造成减速，并禁止跳跃和使用技能</td></tr><tr><td>眩目石身：石化自身，对攻击者造成晕眩和反伤，随后石像爆炸并瞬移至场景固定位置</td></tr><tr><td>致命毒雾：朝空中吐出大量青色气雾，触碰青雾会被长时间沉默并降低跳跃高度，随后定位敌人的位置，在地面召唤蛇头刺出地面攻击</td></tr></tbody></table><h3 id="红蛇婆母" tabindex="-1">红蛇婆母 <a class="header-anchor" href="#红蛇婆母" aria-label="Permalink to “红蛇婆母”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：若未在击败赤蛇分身的5s内击败绿蛇婆母，则二者会合体变回蛇骨婆母，每次合体后血量减半</td></tr><tr><td>连环爪击：红蛇用长指甲抓挠前方造成三连击</td></tr><tr><td>飞袭冲锋：朝敌人方向蓄力后水平飞扑，等待一段时间后再次朝敌人方向进行第二次飞扑攻击</td></tr><tr><td>蚀魂红缎：牵引一条红绳连接自身和敌人，持续抽取对方蓝量，拉开一定距离后红绳可被扯断</td></tr><tr><td>潜影蛇手：瞬移至玩家正上空，手臂向下释放潜影蛇手，随后瞬移至场景固定位置</td></tr><tr><td>蛇斩阵列：在地面召唤出一排排蛇头刺出地面，伤害并击飞敌人</td></tr></tbody></table><h2 id="梦影寺" tabindex="-1">梦影寺 <a class="header-anchor" href="#梦影寺" aria-label="Permalink to “梦影寺”">​</a></h2><h3 id="南方鬼帝" tabindex="-1">南方鬼帝 <a class="header-anchor" href="#南方鬼帝" aria-label="Permalink to “南方鬼帝”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>幽冥鬼雾：挥笔朝目标方向释放一道鬼雾（命中时，若敌人身上有【尸毒】，会给自身回血）</td></tr><tr><td>噬魂鬼符：挥动毛笔画出鬼符，而后朝前方打出鬼符</td></tr><tr><td>幽魂蛇影：定位敌人位置，召唤蛇影出现攻击敌人，并使敌人获得【蛇毒】（蛇影命中时，若敌人身上有【禁锢】，会额外混乱敌人）</td></tr><tr><td>蛛网禁锢：召唤两只小蜘蛛依次从墙顶落下，朝敌人扔出蛛网，使敌人获得【禁锢】（蛛网命中时，若敌人身上有【蛇毒】，会额外混乱敌人）</td></tr><tr><td>致命毒卵：取下腰间蛊罐，持续摇晃，在场景中央召唤一个巨大的毒卵，毒卵爆炸分裂成4个中毒卵朝外移动，移动一段时间后，再次分裂成小毒卵朝外移动</td></tr><tr><td>天鬼降临：鬼帝挥笔画符，而后在场景中央召唤出鬼将（鬼将的所有技能会叠加【尸毒】）<br>天鬼盾击：手持盾牌前冲，而后挥刀攻击敌人<br>天鬼之怒：奋力旋转砍刀，迁引敌人，而后跳起砸地<br>天鬼守护：举起盾牌，给自身添加反伤护盾</td></tr></tbody></table><p>掉落道具：间忏银锁制作书</p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="间忏蛊铃" tabindex="-1">间忏蛊铃 <a class="header-anchor" href="#间忏蛊铃" aria-label="Permalink to “间忏蛊铃”">​</a></h3><img src="'+h+'" alt="间忏蛊铃" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">17~23</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">10~14</td></tr><tr><td style="text-align:center;">吸血</td><td style="text-align:center;">14~19</td></tr><tr><td style="text-align:center;">反伤</td><td style="text-align:center;">14~19</td></tr></tbody></table>',31)])])}const f=a(n,[["render",i]]);export{m as __pageData,f as default};
